import React from 'react';

function HomeHeader() {
    return (
        <header style={{ textAlign: 'center', padding: '40px 20px', backgroundImage: './img/backgroundHomeHeader.png', backgroundSize: 'cover', backgroundPosition: 'center' }}>
            <h1 style={{ fontSize: 32, marginBottom: 12 }}>Bienvenue sur CookBook</h1>
            <p style={{ fontSize: 18, color: '#555' }}>Découvrez des recettes délicieuses et faciles à préparer !</p>
        </header>
    );
}

export default HomeHeader;
